export const suburbOptions = Object.entries(suburbDefaults)
  .map(([key, value]) => ({
    key,
    label: key
      .split("_")
      .map((part) => part.charAt(0).toUpperCase() + part.slice(1))
      .join(" "),
    direction: value.direction,
    lat: value.lat,
    lng: value.lng,
  }))
  .sort((a, b) => a.label.localeCompare(b.label));
